99	    assert compareNoCase(PreAddOp_g, "Add") or compareNoCase(PreAddOp_g, "Sub")
100	        report errorMessage(EntityName_c, "Invalid PreAddOp_g. Allowed values are 'Add' and 'Sub'.")
101	        severity error;
