103	
104	    -- *** Input side ***
105	    -- Pre-adder
106	    g_preadd : if PreAdd_g generate
107	        signal A_0   : std_logic_vector(cl_fix_width(AFmt_c) - 1 downto 0);
108	        signal C_0   : std_logic_vector(cl_fix_width(CFmt_c) - 1 downto 0);
109	        signal B_0   : std_logic_vector(cl_fix_width(BFmt_c) - 1 downto 0);
110	        signal Vld_0 : std_logic;
111	    begin
112	
113	        p_in : process (Clk) is
114	        begin
115	            if rising_edge(Clk) then
116	                -- Stage 0 (input registers)
117	                if InAC_Valid = '1' then
118	                    A_0 <= InA_Data;
119	                    C_0 <= InC_Data;
120	                end if;
121	                if InB_Valid = '1' then
122	                    B_0 <= InB_Data;
123	                end if;
124	
125	                -- Valid handling - do not produce output sample for static coefficient update
126	                if InBIsCoef_g then
127	                    Vld_0 <= InAC_Valid;
128	                else
129	                    Vld_0 <= InAC_Valid or InB_Valid;
130	                end if;
131	
132	                -- Stage 1 - pre add
133	                if compareNoCase(PreAddOp_g, "Add") then
134	                    MulInAC <= cl_fix_add(A_0, AFmt_c, C_0, CFmt_c, PreAddFmt_c);
135	                else
136	                    MulInAC <= cl_fix_sub(A_0, AFmt_c, C_0, CFmt_c, PreAddFmt_c);
137	                end if;
138	                MulInB   <= B_0;
139	                MulInVld <= Vld_0;
140	
