154	    begin
155	
156	        p_in : process (Clk) is
157	        begin
158	            if rising_edge(Clk) then
159	                -- Input Registers
160	                if InAC_Valid = '1' then
161	                    MulInAC <= InA_Data;
162	                end if;
163	                if InB_Valid = '1' then
164	                    MulInB <= InB_Data;
165	                end if;
166	
167	                -- Valid handling - do not produce output sample for static coefficient update
168	                if InBIsCoef_g then
169	                    MulInVld <= InAC_Valid;
170	                else
171	                    MulInVld <= InAC_Valid or InB_Valid;
172	                end if;
173	
174	                -- Reset
175	                if Rst = '1' then
176	                    MulInVld <= '0';
177	                end if;
178	
179	            end if;
180	        end process;
181	
182	    end generate;
