184	    -- *** Multiply / AddSub ***
185	    p_madd : process (Clk) is
186	    begin
187	        if rising_edge(Clk) then
188	            -- Multiply
189	            MulReg(0) <= cl_fix_mult(MulInAC, MultInFmt_c, MulInB, BFmt_c, MultOutFmt_c);
190	
191	            for i in 1 to MultRegs_g - 1 loop
192	                MulReg(i) <= MulReg(i-1);
193	            end loop;
194	
195	            -- Add/Sub
196	            if compareNoCase(Operation_g, "Add") then
197	                Out_Data <= cl_fix_add(MaccIn, AddChainFmt_c, MulReg(MultRegs_g - 1), MultOutFmt_c, AddChainFmt_c);
198	            else
199	                Out_Data <= cl_fix_sub(MaccIn, AddChainFmt_c, MulReg(MultRegs_g - 1), MultOutFmt_c, AddChainFmt_c);
200	            end if;
201	
202	            -- Valid Handling
203	            MulVld(0)               <= MulInVld;
204	            MulVld(1 to MultRegs_g) <= MulVld(0 to MultRegs_g - 1);
205	
206	            -- Reset
207	            if Rst = '1' then
208	                MulVld   <= (others => '0');
209	                Out_Data <= (others => '0');
210	            end if;
211	        end if;
212	    end process;
213	
214	    Out_Valid <= MulVld(MultRegs_g);
