6	
7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements a binary division of two fixed-point numbers using a non-restoring
11	-- division algorithm.
12	--
13	-- Documentation:
14	-- https://github.com/open-logic/open-logic/blob/main/doc/fix/olo_fix_bin_div.md
15	--
16	-- Note: The link points to the documentation of the latest release. If you
17	--       use an older version, the documentation might not match the code.
18	
19	---------------------------------------------------------------------------------------------------
20	-- Libraries
21	---------------------------------------------------------------------------------------------------
22	library ieee;
23	    use ieee.std_logic_1164.all;
24	    use ieee.numeric_std.all;
25	
26	library work;
27	    use work.olo_base_pkg_math.all;
28	    use work.olo_base_pkg_string.all;
29	    use work.en_cl_fix_pkg.all;
30	    use work.olo_fix_pkg.all;
31	
32	---------------------------------------------------------------------------------------------------
33	-- Entity Declaration
34	---------------------------------------------------------------------------------------------------
35	entity olo_fix_bin_div is
36	    generic (
37	        NumFmt_g   : string;
38	        DenomFmt_g : string;
39	        OutFmt_g   : string;
40	        Mode_g     : string := "PIPELINED";
41	        Round_g    : string := FixRound_Trunc_c;
42	        Saturate_g : string := FixSaturate_Sat_c
43	    );
44	    port (
45	        -- Control Signals
46	        Clk       : in    std_logic;
47	        Rst       : in    std_logic;
48	        -- Input
49	        In_Valid  : in    std_logic := '1';
50	        In_Ready  : out   std_logic;
51	        In_Num    : in    std_logic_vector(fixFmtWidthFromString(NumFmt_g)-1 downto 0);
52	        In_Denom  : in    std_logic_vector(fixFmtWidthFromString(DenomFmt_g)-1 downto 0);
53	        -- Output
54	        Out_Valid : out   std_logic;
55	        Out_Quot  : out   std_logic_vector(fixFmtWidthFromString(OutFmt_g)-1 downto 0)
56	    );
57	end entity;
58	
59	---------------------------------------------------------------------------------------------------
60	-- Architecture Declaration
61	---------------------------------------------------------------------------------------------------
62	architecture rtl of olo_fix_bin_div is
63	
64	    -- Formats
65	    constant NumFmt_c     : FixFormat_t   := cl_fix_format_from_string(NumFmt_g);
66	    constant DenomFmt_c   : FixFormat_t   := cl_fix_format_from_string(DenomFmt_g);
67	    constant OutFmt_c     : FixFormat_t   := cl_fix_format_from_string(OutFmt_g);
68	    constant EntityName_c : string        := "olo_fix_bin_div";
69	    constant Round_c      : FixRound_t    := cl_fix_round_from_string(Round_g);
70	    constant Saturate_c   : FixSaturate_t := cl_fix_saturate_from_string(Saturate_g);
71	
72	    -- constants
73	    constant FirstShift_c   : integer     := OutFmt_c.I;
74	    constant NumAbsFmt_c    : FixFormat_t := (0, NumFmt_c.I+NumFmt_c.S, NumFmt_c.F);
75	    constant DenomAbsFmt_c  : FixFormat_t := (0, DenomFmt_c.I+DenomFmt_c.S, DenomFmt_c.F);
76	    constant ResultIntFmt_c : FixFormat_t := (1, OutFmt_c.I+1, OutFmt_c.F+1);
77	    constant DenomCompFmt_c : FixFormat_t := (0, DenomAbsFmt_c.I+FirstShift_c, DenomAbsFmt_c.F-FirstShift_c);
78	    constant NumCompFmt_c   : FixFormat_t := (0, max(DenomCompFmt_c.I, NumAbsFmt_c.I), max(DenomCompFmt_c.F, NumAbsFmt_c.F));
79	    constant Iterations_c   : integer     := OutFmt_c.I+OutFmt_c.F+2;
80	
81	begin
82	
83	    -----------------------------------------------------------------------------------------------
84	    -- Addertions
85	    -----------------------------------------------------------------------------------------------
86	    assert compareNoCase(Mode_g, "PIPELINED") or compareNoCase(Mode_g, "SERIAL")
87	        report errorMessage(EntityName_c, "Mode_g must be PIPELINED or SERIAL")
88	        severity error;
89	
90	    -----------------------------------------------------------------------------------------------
91	    -- Serial implementation
92	    -----------------------------------------------------------------------------------------------
93	    g_serial : if compareNoCase(Mode_g, "SERIAL") generate
94	        -- types
95	        type State_t is (Idle_s, Init1_s, Init2_s, Calc_s, Output_s);
96	
97	        -- Two process method
98	        type TwoProcess_r is record
99	            State     : State_t;
100	            Num       : std_logic_vector(In_Num'range);
101	            Denom     : std_logic_vector(In_Denom'range);
102	            NumSign   : std_logic;
103	            DenomSign : std_logic;
104	            NumAbs    : std_logic_vector(cl_fix_width(NumAbsFmt_c)-1 downto 0);
105	            DenomAbs  : std_logic_vector(cl_fix_width(DenomAbsFmt_c)-1 downto 0);
106	            DenomComp : std_logic_vector(cl_fix_width(DenomCompFmt_c)-1 downto 0);
107	            NumComp   : std_logic_vector(cl_fix_width(NumCompFmt_c)-1 downto 0);
108	            IterCnt   : integer range 0 to Iterations_c-1;
109	            ResultInt : std_logic_vector(cl_fix_width(ResultIntFmt_c)-1 downto 0);
110	            Out_Valid : std_logic;
111	            Out_Quot  : std_logic_vector(cl_fix_width(OutFmt_c)-1 downto 0);
112	            In_Ready  : std_logic;
113	        end record;
114	
115	        signal r, r_next : TwoProcess_r;
116	    begin
117	
118	        -- *** Combinatorial Process ***
119	        p_comb : process (all) is
120	            variable v                : TwoProcess_r;
121	            variable NumIn_DenomFmt_v : std_logic_vector(cl_fix_width(DenomCompFmt_c) -1 downto 0);
122	        begin
123	            -- *** Hold variables stable ***
124	            v := r;
125	
126	            -- *** State Machine ***
127	            v.In_Ready       := '0';
128	            v.Out_Valid      := '0';
129	            NumIn_DenomFmt_v := (others => '0');
130	
131	            case r.State is
132	                when Idle_s =>
133	                    -- start execution if valid
134	                    if In_Valid = '1' then
135	                        v.State := Init1_s;
136	                        v.Num   := In_Num;
137	                        v.Denom := In_Denom;
138	                    else
139	                        v.In_Ready := '1';
140	                    end if;
141	
142	                when Init1_s =>
143	                    -- state handling
144	                    v.State := Init2_s;
145	                    -- latch signs
146	                    if NumFmt_c.S = 0 then
147	                        v.NumSign := '0';
148	                    else
149	                        v.NumSign := r.Num(r.Num'left);
150	                    end if;
151	                    if DenomFmt_c.S = 0 then
152	                        v.DenomSign := '0';
153	                    else
154	                        v.DenomSign := r.Denom(r.Denom'left);
155	                    end if;
156	                    -- calculate absolute values
157	                    v.NumAbs   := cl_fix_abs(r.Num, NumFmt_c, NumAbsFmt_c);
158	                    v.DenomAbs := cl_fix_abs(r.Denom, DenomFmt_c, DenomAbsFmt_c);
159	
160	                when Init2_s =>
161	                    -- state handling
162	                    v.State := Calc_s;
163	                    -- Initialize calculation
164	                    v.DenomComp := cl_fix_shift(r.DenomAbs, DenomAbsFmt_c, FirstShift_c, DenomCompFmt_c);
165	                    v.NumComp   := cl_fix_resize(r.NumAbs, NumAbsFmt_c, NumCompFmt_c);
166	                    v.IterCnt   := Iterations_c-1;
167	                    v.ResultInt := (others => '0');
168	
169	                when Calc_s =>
170	                    -- state handling
171	                    if r.IterCnt = 0 then
172	                        v.State := Output_s;
173	                    else
174	                        v.IterCnt := r.IterCnt - 1;
175	                    end if;
176	
177	                    -- Calculation
178	                    v.ResultInt      := r.ResultInt(r.ResultInt'high-1 downto 0) & '0'; -- shift left
179	                    NumIn_DenomFmt_v := cl_fix_resize(r.NumComp, NumCompFmt_c, DenomCompFmt_c, Trunc_s, None_s);
180	                    if unsigned(r.DenomComp) <= unsigned(NumIn_DenomFmt_v) then
181	                        v.ResultInt(0) := '1';
182	                        v.NumComp      := cl_fix_sub(r.NumComp, NumCompFmt_c, r.DenomComp, DenomCompFmt_c, NumCompFmt_c);
183	                    end if;
184	                    v.NumComp := cl_fix_shift(v.NumComp, NumCompFmt_c, 1, NumCompFmt_c, Trunc_s, Sat_s);
185	
186	                when Output_s =>
187	                    v.State     := Idle_s;
188	                    v.Out_Valid := '1';
189	                    v.In_Ready  := '1';
190	                    if r.NumSign /= r.DenomSign then
191	                        v.Out_Quot := cl_fix_neg(r.ResultInt, ResultIntFmt_c, OutFmt_c, Round_c, Saturate_c);
192	                    else
193	                        v.Out_Quot := cl_fix_resize(r.ResultInt, ResultIntFmt_c, OutFmt_c, Round_c, Saturate_c);
194	                    end if;
195	
196	                -- coverage off
197	                when others => null; -- unreachable
198	                -- coverage on
199	            end case;
200	
201	            -- *** Assign to signal ***
202	            r_next <= v;
203	
204	        end process;
205	
206	        -- *** Outputs ***
207	        Out_Valid <= r.Out_Valid;
208	        Out_Quot  <= r.Out_Quot;
209	        In_Ready  <= r.In_Ready;
210	
211	        -- *** Sequential Proccess ***
212	        p_seq : process (Clk) is
213	        begin
214	            if rising_edge(Clk) then
215	                r <= r_next;
216	                if Rst = '1' then
217	                    r.State     <= Idle_s;
218	                    r.Out_Valid <= '0';
219	                    r.In_Ready  <= '0';
220	                end if;
221	            end if;
222	        end process;
223	
224	    end generate;
225	
226	    -----------------------------------------------------------------------------------------------
227	    -- Pipelined implementation
228	    -----------------------------------------------------------------------------------------------
229	    g_pipelined : if compareNoCase(Mode_g, "PIPELINED") generate
230	
231	        -- types
232	        type DenomComp_a is array (natural range <>) of std_logic_vector(cl_fix_width(DenomCompFmt_c)-1 downto 0);
233	        type NumComp_a is array (natural range <>) of std_logic_vector(cl_fix_width(NumCompFmt_c)-1 downto 0);
234	        type Result_a is array (natural range <>) of std_logic_vector(cl_fix_width(ResultIntFmt_c)-1 downto 0);
235	
236	        -- Two process method
237	        type TwoProcess_r is record
238	            Valid      : std_logic_vector(0 to Iterations_c+3);
239	            Num_0      : std_logic_vector(In_Num'range);
240	            Denom_0    : std_logic_vector(In_Denom'range);
241	            OutNeg     : std_logic_vector(1 to Iterations_c+2);
242	            NumAbs_1   : std_logic_vector(cl_fix_width(NumAbsFmt_c)-1 downto 0);
243	            DenomAbs_1 : std_logic_vector(cl_fix_width(DenomAbsFmt_c)-1 downto 0);
244	            DenomComp  : DenomComp_a(2 to Iterations_c+2);
245	            NumComp    : NumComp_a(2 to Iterations_c+2);
246	            ResultInt  : Result_a(2 to Iterations_c+2);
247	            Out_Quot_N : std_logic_vector(cl_fix_width(OutFmt_c)-1 downto 0);
248	        end record;
249	
250	        signal r, r_next : TwoProcess_r;
251	    begin
252	
253	        -- *** Combinatorial Process ***
254	        p_comb : process (all) is
255	            variable v                : TwoProcess_r;
256	            variable NumIn_DenomFmt_v : std_logic_vector(cl_fix_width(DenomCompFmt_c) -1 downto 0);
257	            variable NumSign_v        : std_logic;
258	            variable DenomSign_v      : std_logic;
259	            variable NextNumComp_v    : std_logic_vector(cl_fix_width(NumCompFmt_c)-1 downto 0);
260	            variable ResultUnsigned_v : std_logic_vector(cl_fix_width(ResultIntFmt_c)-1 downto 0);
261	        begin
262	            -- *** Hold variables stable ***
263	            v := r;
264	
265	            -- *** Update Pipeline ***
266	            v.Valid(v.Valid'low+1 to v.Valid'high)             := r.Valid(r.Valid'low to r.Valid'high-1);
267	            v.OutNeg(v.OutNeg'low+1 to v.OutNeg'high)          := r.OutNeg(r.OutNeg'low to r.OutNeg'high-1);
268	            v.DenomComp(v.DenomComp'low+1 to v.DenomComp'high) := r.DenomComp(r.DenomComp'low to r.DenomComp'high-1);
269	            v.NumComp(v.NumComp'low+1 to v.NumComp'high)       := r.NumComp(r.NumComp'low to r.NumComp'high-1);
270	
271	            -- *** Stage 0 (Input registers) ***
272	            v.Valid(0) := In_Valid;
273	            v.Num_0    := In_Num;
274	            v.Denom_0  := In_Denom;
275	
276	            -- *** Stage 1 (Remove Sign) ***
277	            v.NumAbs_1   := cl_fix_abs(r.Num_0, NumFmt_c, NumAbsFmt_c);
278	            v.DenomAbs_1 := cl_fix_abs(r.Denom_0, DenomFmt_c, DenomAbsFmt_c);
279	            if NumFmt_c.S = 0 then
280	                NumSign_v := '0';
281	            else
282	                NumSign_v := r.Num_0(r.Num_0'left);
283	            end if;
284	            if DenomFmt_c.S = 0 then
285	                DenomSign_v := '0';
286	            else
287	                DenomSign_v := r.Denom_0(r.Denom_0'left);
288	            end if;
289	            v.OutNeg(1) := NumSign_v xor DenomSign_v;
290	
291	            -- *** Stage 2 (Initialization) ***
292	            v.DenomComp(2) := cl_fix_shift(r.DenomAbs_1, DenomAbsFmt_c, FirstShift_c, DenomCompFmt_c);
293	            v.NumComp(2)   := cl_fix_resize(r.NumAbs_1, NumAbsFmt_c, NumCompFmt_c);
294	            v.ResultInt(2) := (others => '0');
295	
296	            -- *** Stages 3-N (Calculation) ***
297	            -- Default Value to avoid latches
298	            NumIn_DenomFmt_v := (others => '0');
299	
300	            -- Iterations
301	            for stg in 3 to 2+Iterations_c loop
302	                v.ResultInt(stg) := r.ResultInt(stg-1)(r.ResultInt(stg-1)'high-1 downto 0) & '0'; -- shift left
303	                NextNumComp_v    := r.NumComp(stg-1);
304	                NumIn_DenomFmt_v := cl_fix_resize(r.NumComp(stg-1), NumCompFmt_c, DenomCompFmt_c, Trunc_s, None_s);
305	                if unsigned(r.DenomComp(stg-1)) <= unsigned(NumIn_DenomFmt_v) then
306	                    v.ResultInt(stg)(0) := '1';
307	                    NextNumComp_v       := cl_fix_sub(r.NumComp(stg-1), NumCompFmt_c, r.DenomComp(stg-1), DenomCompFmt_c, NumCompFmt_c);
308	                end if;
309	                v.NumComp(stg) := cl_fix_shift(NextNumComp_v, NumCompFmt_c, 1, NumCompFmt_c, Trunc_s, Sat_s);
310	            end loop;
311	
312	            -- *** Stage N+1 (Output) ***
313	            ResultUnsigned_v := r.ResultInt(2+Iterations_c);
314	            if r.OutNeg(2+Iterations_c) = '1' then
315	                v.Out_Quot_N := cl_fix_neg(ResultUnsigned_v, ResultIntFmt_c, OutFmt_c, Round_c, Saturate_c);
316	            else
317	                v.Out_Quot_N := cl_fix_resize(ResultUnsigned_v, ResultIntFmt_c, OutFmt_c, Round_c, Saturate_c);
318	            end if;
319	
320	            -- *** Assign to signal ***
321	            r_next <= v;
322	
323	        end process;
324	
325	        -- *** Outputs ***
326	        Out_Valid <= r.Valid(r.Valid'high);
327	        Out_Quot  <= r.Out_Quot_N;
328	        In_Ready  <= '1';
329	
330	        -- *** Sequential Proccess ***
331	        p_seq : process (Clk) is
332	        begin
333	            if rising_edge(Clk) then
334	                r <= r_next;
335	                if Rst = '1' then
336	                    r.Valid <= (others => '0');
337	                end if;
338	            end if;
339	        end process;
340	
341	    end generate;
342	
343	end architecture;
344	
345	
346	
347	
348	
