26	    use work.olo_test_fix_stimuli_pkg.all;
27	    use work.olo_test_fix_checker_pkg.all;
28	
29	---------------------------------------------------------------------------------------------------
30	-- Entity
31	---------------------------------------------------------------------------------------------------
32	-- vunit: run_all_in_same_sim
33	entity olo_fix_madd_tb is
34	    generic (
35	        PreAdd_g      : boolean := false;
36	        Operation_g   : string  := "Add";
37	        PreAddOp_g    : string  := "Add";
38	        MultRegs_g    : natural := 1;
39	        InBIsCoef_g   : boolean := false;
40	        runner_cfg    : string
41	    );
42	end entity;
43	
44	architecture sim of olo_fix_madd_tb is
45	
46	    -----------------------------------------------------------------------------------------------
47	    -- TB Defnitions
48	    -----------------------------------------------------------------------------------------------
49	    constant Clk_Frequency_c : real := 100.0e6; -- 100 MHz
50	    constant Clk_Period_c    : time := (1 sec) / Clk_Frequency_c;
51	
52	    constant AFmt_c        : FixFormat_t := (1, 7, 0);
53	    constant CFmt_c        : FixFormat_t := (1, 8, 0);
54	    constant BFmt_c        : FixFormat_t := (1, 6, 0);
55	    constant AddChainFmt_c : FixFormat_t := (1, 24, 0);
56	
57	    -----------------------------------------------------------------------------------------------
58	    -- Interface Signals
59	    -----------------------------------------------------------------------------------------------
60	    signal Clk        : std_logic                                                  := '0';
61	    signal Rst        : std_logic                                                  := '0';
62	    signal InA_Data   : std_logic_vector(cl_fix_width(AFmt_c) - 1 downto 0)        := (others => '0');
63	    signal InB_Data   : std_logic_vector(cl_fix_width(BFmt_c) - 1 downto 0)        := (others => '0');
64	    signal InC_Data   : std_logic_vector(cl_fix_width(CFmt_c) - 1 downto 0)        := (others => '0');
65	    signal MaccIn     : std_logic_vector(cl_fix_width(AddChainFmt_c) - 1 downto 0) := (others => '0');
66	    signal InAC_Valid : std_logic                                                  := '0';
67	    signal InB_Valid  : std_logic                                                  := '0';
68	    signal Out_Valid  : std_logic;
69	    signal Out_Data   : std_logic_vector(cl_fix_width(AddChainFmt_c) - 1 downto 0);
70	
71	begin
72	
73	    -----------------------------------------------------------------------------------------------
74	    -- TB Control
75	    -----------------------------------------------------------------------------------------------
76	    test_runner_watchdog(runner, 1 ms);
77	
78	    p_control : process is
79	        variable A_v, B_v, C_v, Macc_v, Result_v, AC_v       : real;
80	        variable A2_v, B2_v, C2_v, Macc2_v, Result2_v, AC2_v : real;
81	    begin
82	        test_runner_setup(runner, runner_cfg);
83	
84	        while test_suite loop
85	
86	            -- Reset
87	            wait until rising_edge(Clk);
88	            Rst <= '1';
89	            wait for 1 us;
90	            wait until rising_edge(Clk);
91	            Rst <= '0';
92	
93	            -- *** Reset State ***
94	            if run("ResetState") then
95	                check_equal(Out_Valid, '0', "Out_Valid should be '0' after reset");
96	                check_equal(Out_Data, 0, "Out_Data should be '0' after reset");
97	            end if;
98	
99	            -- *** Spaced Samples ***
100	            if run("SpacedSamples") then
101	
102	                for i in 0 to 1 loop
103	                    -- Calculate Testcase
104	                    A_v    := 1.0 + real(i*10);
105	                    B_v    := 2.0 + real(i*10);
106	                    C_v    := 3.0 + real(i*10);
107	                    Macc_v := 4.0;
108	                    if PreAdd_g then
109	                        if PreAddOp_g = "Add" then
110	                            AC_v := A_v + C_v;
111	                        else
112	                            AC_v := A_v - C_v;
113	                        end if;
114	                    else
115	                        AC_v := A_v;
116	                    end if;
117	                    if Operation_g = "Add" then
118	                        Result_v := Macc_v + AC_v * B_v;
119	                    else
120	                        Result_v := Macc_v - AC_v * B_v;
121	                    end if;
122	
123	                    -- Execute
124	                    wait until falling_edge(Clk);
125	                    check_equal(Out_Valid, '0', "Unexpected Out_Valid");
126	                    InA_Data   <= cl_fix_from_real(A_v, AFmt_c);
127	                    InB_Data   <= cl_fix_from_real(B_v, BFmt_c);
128	                    InC_Data   <= cl_fix_from_real(C_v, CFmt_c);
129	                    MaccIn     <= (others => 'X');
130	                    InAC_Valid <= '1';
131	                    InB_Valid  <= '1';
132	                    -- In reg
133	                    wait until falling_edge(Clk);
134	                    check_equal(Out_Valid, '0', "Unexpected Out_Valid");
135	                    InAC_Valid <= '0';
136	                    InB_Valid  <= '0';
137	                    InA_Data   <= (others => 'X');
138	                    InB_Data   <= (others => 'X');
139	                    InC_Data   <= (others => 'X');
140	                    -- adder
141	                    if PreAdd_g then
142	                        wait until falling_edge(Clk);
143	                        check_equal(Out_Valid, '0', "Unexpected Out_Valid");
144	                    end if;
145	                    -- Mult Regs
146	
147	                    for i in 0 to MultRegs_g - 1 loop
148	                        wait until falling_edge(Clk);
149	                        check_equal(Out_Valid, '0', "Unexpected Out_Valid");
150	                    end loop;
151	
152	                    MaccIn <= cl_fix_from_real(Macc_v, AddChainFmt_c);
153	                    -- Output Reg
154	                    wait until falling_edge(Clk);
155	                    MaccIn <= (others => 'X');
156	                    check_equal(Out_Valid, '1', "Out_Valid should be '1' for valid output sample");
157	                    check_equal(Out_Data, cl_fix_from_real(Result_v, AddChainFmt_c), "Output data mismatch");
158	                    -- Wait a bit
159	                    wait until falling_edge(Clk);
160	                    check_equal(Out_Valid, '0', "Unexpected Out_Valid");
161	                    wait until falling_edge(Clk);
162	                    wait until falling_edge(Clk);
163	                end loop;
164	
165	            end if;
166	
167	            -- *** Back to back samples ***
168	            if run("BackToBackSamples") then
169	                -- Calculate Testcase 0
170	                A_v    := 1.0;
171	                B_v    := 2.0;
172	                C_v    := 3.0;
173	                Macc_v := 4.0;
174	                if PreAdd_g then
175	                    if PreAddOp_g = "Add" then
176	                        AC_v := A_v + C_v;
177	                    else
178	                        AC_v := A_v - C_v;
179	                    end if;
180	                else
181	                    AC_v := A_v;
182	                end if;
183	                if Operation_g = "Add" then
184	                    Result_v := Macc_v + AC_v * B_v;
185	                else
186	                    Result_v := Macc_v - AC_v * B_v;
187	                end if;
188	
189	                -- Calculate Testcase 1
190	                A2_v    := 11.0;
191	                B2_v    := 12.0;
192	                C2_v    := 13.0;
193	                Macc2_v := 14.0;
194	                if PreAdd_g then
195	                    if PreAddOp_g = "Add" then
196	                        AC2_v := A2_v + C2_v;
197	                    else
198	                        AC2_v := A2_v - C2_v;
199	                    end if;
200	                else
201	                    AC2_v := A2_v;
202	                end if;
203	                if Operation_g = "Add" then
204	                    Result2_v := Macc2_v + AC2_v * B2_v;
205	                else
206	                    Result2_v := Macc2_v - AC2_v * B2_v;
207	                end if;
208	
209	                -- Execute / -
210	                wait until falling_edge(Clk);
211	                check_equal(Out_Valid, '0', "Unexpected Out_Valid");
212	                InA_Data   <= cl_fix_from_real(A_v, AFmt_c);
213	                InB_Data   <= cl_fix_from_real(B_v, BFmt_c);
214	                InC_Data   <= cl_fix_from_real(C_v, CFmt_c);
215	                MaccIn     <= (others => 'X');
216	                InAC_Valid <= '1';
217	                InB_Valid  <= '1';
218	
219	                -- In reg
220	                wait until falling_edge(Clk);
221	                InA_Data <= cl_fix_from_real(A2_v, AFmt_c);
222	                InB_Data <= cl_fix_from_real(B2_v, BFmt_c);
223	                InC_Data <= cl_fix_from_real(C2_v, CFmt_c);
224	                check_equal(Out_Valid, '0', "Unexpected Out_Valid");
225	                -- adder
226	                if PreAdd_g then
227	                    wait until falling_edge(Clk);
228	                    InAC_Valid <= '0';
229	                    InB_Valid  <= '0';
230	                    check_equal(Out_Valid, '0', "Unexpected Out_Valid");
231	                end if;
232	                -- Mult Regs
233	
234	                for i in 0 to MultRegs_g - 1 loop
235	                    wait until falling_edge(Clk);
236	                    InAC_Valid <= '0';
237	                    InB_Valid  <= '0';
238	                    check_equal(Out_Valid, '0', "Unexpected Out_Valid");
239	                end loop;
240	
241	                MaccIn <= cl_fix_from_real(Macc_v, AddChainFmt_c);
242	                -- Output Reg 0
243	                wait until falling_edge(Clk);
244	                MaccIn <= cl_fix_from_real(Macc2_v, AddChainFmt_c);
245	                check_equal(Out_Valid, '1', "Out_Valid should be '1' for valid output sample");
246	                check_equal(Out_Data, cl_fix_from_real(Result_v, AddChainFmt_c), "Output data mismatch");
247	                -- Output Reg 1
248	                wait until falling_edge(Clk);
249	                MaccIn <= (others => 'X');
250	                check_equal(Out_Valid, '1', "Out_Valid should be '1' for valid output sample");
251	                check_equal(Out_Data, cl_fix_from_real(Result2_v, AddChainFmt_c), "Output data mismatch");
252	                -- Wait a bit
253	                wait until falling_edge(Clk);
254	                check_equal(Out_Valid, '0', "Unexpected Out_Valid");
255	                wait until falling_edge(Clk);
256	                wait until falling_edge(Clk);
257	            end if;
258	
259	            -- *** Coef Latching ***
260	            if run("CoefLatching") then
261	                -- Skip case if coefficient is not static
262	                if InBIsCoef_g then
263	                    -- Calculate Testcase
264	                    A_v    := 1.0;
265	                    B_v    := 2.0;
266	                    C_v    := 3.0;
267	                    Macc_v := 4.0;
268	                    if PreAdd_g then
269	                        if PreAddOp_g = "Add" then
270	                            AC_v := A_v + C_v;
271	                        else
272	                            AC_v := A_v - C_v;
273	                        end if;
274	                    else
275	                        AC_v := A_v;
276	                    end if;
277	                    if Operation_g = "Add" then
278	                        Result_v := Macc_v + AC_v * B_v;
279	                    else
280	                        Result_v := Macc_v - AC_v * B_v;
281	                    end if;
282	
283	                    -- Latch coefficient and check not output valid
284	                    wait until falling_edge(Clk);
285	                    InB_Data  <= cl_fix_from_real(B_v, BFmt_c);
286	                    InB_Valid <= '1';
287	                    wait until falling_edge(Clk);
288	                    InB_Valid <= '0';
289	                    InB_Data  <= (others => 'X');
290	
291	                    for i in 0 to 10 loop
292	                        check_equal(Out_Valid, '0', "Unexpected Out_Valid while latching coefficient");
293	                        wait until falling_edge(Clk);
294	                    end loop;
295	
296	                    -- Execute
297	                    wait until falling_edge(Clk);
298	                    check_equal(Out_Valid, '0', "Unexpected Out_Valid");
299	                    InA_Data   <= cl_fix_from_real(A_v, AFmt_c);
300	                    InC_Data   <= cl_fix_from_real(C_v, CFmt_c);
301	                    MaccIn     <= cl_fix_from_real(Macc_v, AddChainFmt_c);
302	                    InAC_Valid <= '1';
303	                    -- In reg
304	                    wait until falling_edge(Clk);
305	                    check_equal(Out_Valid, '0', "Unexpected Out_Valid");
306	                    InAC_Valid <= '0';
307	                    InA_Data   <= (others => 'X');
308	                    InC_Data   <= (others => 'X');
309	                    -- adder
310	                    if PreAdd_g then
311	                        wait until falling_edge(Clk);
312	                        check_equal(Out_Valid, '0', "Unexpected Out_Valid");
313	                    end if;
314	                    -- Mult Regs
315	
316	                    for i in 0 to MultRegs_g - 1 loop
317	                        wait until falling_edge(Clk);
318	                        check_equal(Out_Valid, '0', "Unexpected Out_Valid");
319	                    end loop;
320	
321	                    -- Output Reg
322	                    wait until falling_edge(Clk);
323	                    check_equal(Out_Valid, '1', "Out_Valid should be '1' for valid output sample");
324	                    check_equal(Out_Data, cl_fix_from_real(Result_v, AddChainFmt_c), "Output data mismatch");
325	                end if;
326	            end if;
327	
328	            wait for 1 us;
329	
330	        end loop;
331	
332	        -- TB done
333	        test_runner_cleanup(runner);
334	    end process;
335	
336	    -----------------------------------------------------------------------------------------------
337	    -- Clock
338	    -----------------------------------------------------------------------------------------------
339	    Clk <= not Clk after 0.5*Clk_Period_c;
340	
341	    -----------------------------------------------------------------------------------------------
342	    -- DUT
343	    -----------------------------------------------------------------------------------------------
344	    i_dut : entity olo.olo_fix_madd
345	        generic map (
346	            PreAdd_g      => PreAdd_g,
347	            Operation_g   => Operation_g,
348	            PreAddOp_g    => PreAddOp_g,
349	            InBIsCoef_g   => InBIsCoef_g,
350	            AFmt_g        => to_string(AFmt_c),
351	            BFmt_g        => to_string(BFmt_c),
352	            CFmt_g        => to_string(CFmt_c),
353	            AddChainFmt_g => to_string(AddChainFmt_c),
354	            MultRegs_g    => MultRegs_g
355	        )
356	        port map (
357	            Clk         => Clk,
358	            Rst         => Rst,
359	            InA_Data    => InA_Data,
360	            InB_Data    => InB_Data,
361	            InC_Data    => InC_Data,
362	            InAC_Valid  => InAC_Valid,
363	            InB_Valid   => InB_Valid,
364	            MaccIn      => MaccIn,
365	            Out_Valid   => Out_Valid,
366	            Out_Data    => Out_Data
367	        );
368	
369	end architecture;
